// ─── 중복 코드 제거 후 합산 풀 ────────────────────────────────────────────────
const deduped = (pool: StockItem[]): StockItem[] => {
  const seen = new Set<string>()
  return pool.filter(s => {
    if (seen.has(s.code)) return false
    seen.add(s.code)
    return true
  })
}

export const ALL_STOCK_POOL: StockItem[] = [
  ...deduped(KOSPI_POOL),
  ...deduped(KOSDAQ_POOL),
]
